#![allow(
    clippy::unwrap_used,
    clippy::expect_used,
    clippy::doc_markdown,
    clippy::useless_format,
    clippy::uninlined_format_args,
    clippy::items_after_statements,
    clippy::indexing_slicing,
)]

use mqo_eval::{
    run::{run, OutputFormat, RunConfig},
    types::OracleMode,
};

/// Helper: write a stub agent script that returns a fixed JSON payload.
///
/// Returns the path as a string; the caller must keep the tempdir alive.
fn write_stub_agent(dir: &tempfile::TempDir, answer: &str) -> String {
    let path = dir.path().join("stub_agent.sh");
    let script = format!(
        "#!/bin/sh\necho '{{\"bound_mqo\":\"stub\",\"result_rows\":[[\"{answer}\"]],\"confidence\":0.9,\"pillars_fired\":[\"bind\"]}}'\n",
        answer = answer
    );
    std::fs::write(&path, script).expect("write stub script");
    // Make executable.
    use std::os::unix::fs::PermissionsExt;
    let mut perms = std::fs::metadata(&path).expect("metadata").permissions();
    perms.set_mode(0o755);
    std::fs::set_permissions(&path, perms).expect("set permissions");
    path.to_string_lossy().into_owned()
}

/// Helper: write a 5-entry fixture questions YAML.
fn write_questions_yaml(tmp: &tempfile::TempDir) -> String {
    let path = tmp.path().join("questions.yaml");
    let yaml = r#"questions:
  - id: q1
    text: "What is total revenue?"
    expected_answer: "1234567.89"
    model: tasty_bytes/sales
  - id: q2
    text: "How many orders?"
    expected_answer: "999"
    model: tasty_bytes/sales
  - id: q3
    text: "Average order value?"
    expected_answer: "1235.0"
    model: tasty_bytes/sales
  - id: q4
    text: "Top region by revenue?"
    expected_answer: "West"
    model: tasty_bytes/sales
  - id: q5
    text: "YoY growth rate?"
    expected_answer: "0.12"
    model: tasty_bytes/sales
"#;
    std::fs::write(&path, yaml).expect("write questions yaml");
    path.to_string_lossy().into_owned()
}

#[test]
fn acceptance_ac1() {
    let tmp = tempfile::tempdir().expect("tempdir");
    let questions_path = write_questions_yaml(&tmp);
    let out_path = tmp.path().join("results.json");
    let agent_cmd = write_stub_agent(&tmp, "1234567.89");

    let config = RunConfig {
        questions_path,
        model: "tasty_bytes/sales".to_owned(),
        agent_cmd,
        oracle: OracleMode::Fixture,
        pg_host: None,
        pg_pass_env: "ATSCALE_PG_PASS".to_owned(),
        catalog_name: "atscale_catalogs".to_owned(),
        model_name: "tpcds_benchmark_model".to_owned(),
        max_result_rows: 50_000,
        pg_user: "atscale".to_owned(),
        out_path: out_path.to_string_lossy().into_owned(),
        format: OutputFormat::Text,
        results_dir: tmp.path().join("results").to_string_lossy().into_owned(),
    };

    let results = run(&config).expect("run should succeed with fixture oracle offline");

    // Should produce exactly 5 results.
    assert_eq!(results.len(), 5, "expected 5 question results");

    // results.json must exist and be valid JSON.
    let json_text = std::fs::read_to_string(&out_path).expect("results.json should be written");
    let parsed: serde_json::Value =
        serde_json::from_str(&json_text).expect("results.json must be valid JSON");
    assert!(parsed.is_array(), "results.json must be a JSON array");
    assert_eq!(parsed.as_array().unwrap().len(), 5);
}
